/**
 * Função recursiva que percorre dados e substitui valores "(none)" por "".
 * @param {*} data - Pode ser um objeto, array ou valor primitivo.
 * @returns {*} - Dados com as substituições aplicadas.
 */
function replaceNone(data) {
  if (Array.isArray(data)) {
    // Trata se for array
    return data.map(element => replaceNone(element));
  }
  if (data !== null && typeof data === 'object') {
    // Trata se for objeto
    const newObj = {};
    for (const [key, value] of Object.entries(data)) {
      newObj[key] = replaceNone(value);
    }
    return newObj;
  }
  // Se for valor primitivo, verifica se é "(none)" para substituição
  return data === "(none)" ? null : data;
}

// O n8n injeta os itens com o formato { json: {...} }
// Mapeia cada item e aplica a função no campo json
return items.map(item => ({
  json: replaceNone(item.json),
}));

